import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface IArenaLeaderboardEntry
{
userId: number;
username: string;
figure: string;
level: number;
wins: number;
losses: number;
}

export class ArenaLeaderboardParser implements IMessageParser
{
private _entries: IArenaLeaderboardEntry[] = [];

public flush(): boolean
{
this._entries = [];
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

this._entries = [];

// 1) total rows
const total = wrapper.readInt();

for(let i = 0; i < total; i++)
{
const userId = wrapper.readInt();
const username = wrapper.readString();
const figure = wrapper.readString();
const level = wrapper.readInt();
const wins = wrapper.readInt();
const losses = wrapper.readInt();

this._entries.push({
userId,
username,
figure,
level,
wins,
losses
});
}

return true;
}

public get entries(): IArenaLeaderboardEntry[]
{
return this._entries;
}
}
